import { useState, useEffect } from "react";
import { Container } from "react-bootstrap";
import axios from "axios";
import { Link } from "react-router-dom";
import moment from "moment";

const Blogs = () => {
  const api =
    "https://api.rss2json.com/v1/api.json?rss_url=https://medium.com/feed/@siddharth.tumre";
  const [posts, setPosts] = useState([]);

  useEffect(() => {
    const fetchPosts = async () => {
      try {
        const response = await axios.get(api);
        const { data } = response;
        setPosts(data.items); // Assuming the API response has a 'posts' property containing the posts data
      } catch (error) {
        console.error("Error fetching posts:", error);
      }
    };

    fetchPosts();
  }, []);

  console.log(posts);
  return (
    <Container className="px-5 mt-5">
      <div className="large-heading">Blog Articles</div>
      <ol>
        {posts.map((post) => (
          <li>
            <Link className="link mb-3" target="_blank" to={post.link}>
              {post.title}
            </Link>{" "}
            <br />
            {moment(post.pubDate).format("MMM DD, YYYY")}
          </li>
        ))}
      </ol>
    </Container>
  );
};

export default Blogs;
