import { Outlet, NavLink } from "react-router-dom";
import styles from './layout.module.css'; 
import { Container } from "react-bootstrap";
import CV from '../CV_May23.pdf';

const Layout = () => {
  return (
    <>
        <Container className={styles.navbar}>
            <NavLink className={styles.navlink} style={({isActive})=>{return{color: isActive?'white':''}}} to="/">Home</NavLink>
            <NavLink className={styles.navlink} style={({isActive})=>{return{color: isActive?'white':''}}} to="/blogs">Blog</NavLink>
            <NavLink className={styles.navlink} style={({isActive})=>{return{color: isActive?'white':''}}} to={CV} target="_blank">CV</NavLink>
            <NavLink className={styles.navlink} style={({isActive})=>{return{color: isActive?'white':''}}} to="/contact">Contact</NavLink>
        </Container>
      <Outlet />
    </>
  )
};

export default Layout;